#include<bits/stdc++.h>
using namespace std;
long long l,h,r,cnt,b[10005];
int main() {
	while(cin>>l>>h>>r) {
		for(long long i=l; i<r; i++) {
			b[i]=max(b[i],h);
		}
	}
	for(long long i=1; i<=10000; i++) {
		if(cnt!=b[i]) {
			cnt=b[i];
			cout<<i<<" "<<b[i]<<" ";
		}
	}
	return 0;
}
